import type {
  AreaSeriesWithDatapoints,
  LineSeriesWithDatapoints,
  XYChartAxisInternal,
} from '../../types/xy-chart-internals.js';
import type { AreaDatapoint, LineDatapoint } from '../../types/xy-chart.js';
import { detectGapBetweenDatapoints } from '../utils/gap/get-gap-policy-information.js';

export class GappableSeriesHelper<T extends AreaDatapoint | LineDatapoint> {
  private readonly lastDatapointPerSeries: Map<string, T>;

  constructor() {
    this.lastDatapointPerSeries = new Map();
  }

  /** Given a current series, it detects gaps between consecutive datapoints */
  public handleGapDetection(
    datapoint: T,
    currentSeries: LineSeriesWithDatapoints | AreaSeriesWithDatapoints,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
  ) {
    const lastDatapoint = this.lastDatapointPerSeries.get(currentSeries.id);

    let gappedDatapoint: T | undefined;

    if (lastDatapoint) {
      const isGap = detectGapBetweenDatapoints(
        lastDatapoint,
        datapoint,
        xAxis,
        yAxis,
      );

      if (isGap) {
        gappedDatapoint = { ...datapoint };
      }
    }

    this.lastDatapointPerSeries.set(currentSeries.id, datapoint);

    return gappedDatapoint;
  }
}
